// 获取随机诗
export function getRandomPoem(): Poem {
  const index = Math.floor(Math.random() * poems.length);
  return poems[index];
}

// 按索引获取诗
export function getPoemByIndex(index: number): Poem {
  return poems[index % poems.length];
}

// 获取诗的总数
export function getPoemCount(): number {
  return poems.length;
}
